716:     Length(Length),
717:     Percentage(Percentage),
718:     Number(f32),
719: }
720: 
721: impl CalcLengthPercentageLeaf {
722:     fn is_zero_length(&self) -> bool {
723:         match *self {
724:             Self::Length(ref l) => l.is_zero(),
725:             Self::Percentage(..) => false,
726:             Self::Number(..) => false,
727:         }
728:     }
729: }
730: 
731: impl calc::CalcNodeLeaf for CalcLengthPercentageLeaf {
732:     fn unit(&self) -> CalcUnits {
733:         match self {
734:             Self::Length(_) => CalcUnits::LENGTH,
735:             Self::Percentage(_) => CalcUnits::PERCENTAGE,
736:             Self::Number(_) => CalcUnits::empty(),
737:         }
738:     }
739: 
740:     fn unitless_value(&self) -> Option<f32> {
741:         Some(match *self {
742:             Self::Length(ref l) => l.px(),
743:             Self::Percentage(ref p) => p.0,
744:             Self::Number(n) => n,
745:         })
746:     }
747: 
748:     fn new_number(value: f32) -> Self {
749:         Self::Number(value)
750:     }
751: 
752:     fn as_number(&self) -> Option<f32> {
753:         match *self {
754:             Self::Length(_) | Self::Percentage(_) => None,
755:             Self::Number(value) => Some(value),
756:         }
757:     }
758: 
759:     fn compare(&self, other: &Self, basis: PositivePercentageBasis) -> Option<std::cmp::Ordering> {
760:         use self::CalcLengthPercentageLeaf::*;
761:         if std::mem::discriminant(self) != std::mem::discriminant(other) {
762:             return None;
763:         }
764: 
765:         if matches!(self, Percentage(..)) && matches!(basis, PositivePercentageBasis::Unknown) {
766:             return None;
767:         }
768: 
769:         let Ok(self_negative) = self.is_negative() else {
770:             return None;
771:         };
772:         let Ok(other_negative) = other.is_negative() else {
773:             return None;
774:         };
775:         if self_negative != other_negative {
776:             return Some(if self_negative {
777:                 std::cmp::Ordering::Less
778:             } else {
779:                 std::cmp::Ordering::Greater
780:             });
781:         }
782: 
783:         match (self, other) {
784:             (&Length(ref one), &Length(ref other)) => one.partial_cmp(other),
785:             (&Percentage(ref one), &Percentage(ref other)) => one.partial_cmp(other),
786:             (&Number(ref one), &Number(ref other)) => one.partial_cmp(other),
787:             _ => unsafe {
788:                 match *self {
789:                     Length(..) | Percentage(..) | Number(..) => {},
790:                 }
791:                 debug_unreachable!("Forgot to handle unit in compare()")
792:             },
793:         }
794:     }
795: 
796:     fn try_sum_in_place(&mut self, other: &Self) -> Result<(), ()> {
797:         use self::CalcLengthPercentageLeaf::*;
798: 
799:         // 0px plus anything else is equal to the right hand side.
800:         if self.is_zero_length() {
801:             *self = other.clone();
802:             return Ok(());
803:         }
804: 
805:         if other.is_zero_length() {
806:             return Ok(());
807:         }
808: 
809:         if std::mem::discriminant(self) != std::mem::discriminant(other) {
810:             return Err(());
811:         }
812: 
813:         match (self, other) {
814:             (&mut Length(ref mut one), &Length(ref other)) => {
815:                 *one += *other;
816:             },
817:             (&mut Percentage(ref mut one), &Percentage(ref other)) => {
818:                 one.0 += other.0;
819:             },
820:             (&mut Number(ref mut one), &Number(ref other)) => {
821:                 *one += *other;
822:             },
823:             _ => unsafe {
824:                 match *other {
825:                     Length(..) | Percentage(..) | Number(..) => {},
826:                 }
827:                 debug_unreachable!("Forgot to handle unit in try_sum_in_place()")
828:             },
829:         }
830: 
831:         Ok(())
832:     }
833: 
834:     fn try_product_in_place(&mut self, other: &mut Self) -> bool {
835:         if let Self::Number(ref mut left) = *self {
836:             if let Self::Number(ref right) = *other {
837:                 // Both sides are numbers, so we can just modify the left side.
838:                 *left *= *right;
839:                 true
840:             } else {
841:                 // The right side is not a number, so the result should be in the units of the right
842:                 // side.
843:                 if other.map(|v| v * *left).is_ok() {
844:                     std::mem::swap(self, other);
845:                     true
846:                 } else {
847:                     false
848:                 }
849:             }
850:         } else if let Self::Number(ref right) = *other {
851:             // The left side is not a number, but the right side is, so the result is the left
852:             // side unit.
853:             self.map(|v| v * *right).is_ok()
854:         } else {
855:             // Neither side is a number, so a product is not possible.
856:             false
857:         }
858:     }
859: 
860:     fn try_op<O>(&self, other: &Self, op: O) -> Result<Self, ()>
861:     where
862:         O: Fn(f32, f32) -> f32,
863:     {
864:         use self::CalcLengthPercentageLeaf::*;
865:         if std::mem::discriminant(self) != std::mem::discriminant(other) {
866:             return Err(());
867:         }
868:         Ok(match (self, other) {
869:             (&Length(ref one), &Length(ref other)) => {
870:                 Length(super::Length::new(op(one.px(), other.px())))
871:             },
872:             (&Percentage(one), &Percentage(other)) => {
873:                 Self::Percentage(super::Percentage(op(one.0, other.0)))
874:             },
875:             (&Number(one), &Number(other)) => Self::Number(op(one, other)),
876:             _ => unsafe {
877:                 match *self {
878:                     Length(..) | Percentage(..) | Number(..) => {},
879:                 }
880:                 debug_unreachable!("Forgot to handle unit in try_op()")
881:             },
882:         })
883:     }
884: 
885:     fn map(&mut self, mut op: impl FnMut(f32) -> f32) -> Result<(), ()> {
886:         Ok(match self {
887:             Self::Length(value) => {
888:                 *value = Length::new(op(value.px()));
889:             },
890:             Self::Percentage(value) => {
891:                 *value = Percentage(op(value.0));
892:             },
893:             Self::Number(value) => {
894:                 *value = op(*value);
895:             },
896:         })
897:     }
898: 
899:     fn simplify(&mut self) {}
